external_knowledge:
- "Older folks" refers to passengers aged over 50;
- "Better classes" are the 1st or 2nd classes;
- "Sizable families" are those with a family size of greater than five;
- "Survival stories" refers to the descriptive survival status of passengers.

sql:
SELECT passengers.passenger_id, passengers.survived, passengers.pclass, fares.fare, passengers.sex, passengers.age
FROM passengers
INNER JOIN fares ON passengers.passenger_id = fares.passenger_id;
